 1	import React, { useCallback, useEffect, useRef, useState } from 'react';
 2	import { Stack, TextInput } from '@patternfly/react-core';
 3	import { Button } from '@patternfly/react-core';
 4	import { TraceQLEditor } from './TraceQLEditor';
 5	import { useTranslation } from 'react-i18next';
 6	import { TempoInstance } from '../../../hooks/useTempoInstance';
 7	import { TempoTraceQuerySpec } from '@perses-dev/tempo-plugin';
 8	
 9	interface QueryEditorProps {
10	  tempo: TempoInstance | undefined;
11	  query: string;
12	  limit: number;
13	  runQuery: (spec: TempoTraceQuerySpec) => void;
14	}
15	
16	export const DEFAULT_LIMIT = 20;
17	const MAX_LIMIT = 10000;
18	
19	export function QueryEditor({ tempo, query, limit, runQuery }: QueryEditorProps) {
20	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
21	
22	  // The 'query' prop contains the current executed query.
23	  // For performance and UX reasons, the search results should not be refreshed on every key press.
24	  // Also, the query editor should not be re-rendered on every key press.
25	  // Therefore we create a derived state, 'pendingQuery', which holds the current query from the editor (which may or may have been executed).
26	  const pendingQuery = useRef<string>(query);
27	  const setPendingQuery = useCallback((query: string) => {
28	    pendingQuery.current = query;
29	  }, []);
30	  // If the query editor re-renders (for example because of the "Clear all filters" button of the empty results state),
31	  // sync the pendingQuery with the executed query.
32	  useEffect(() => {
33	    pendingQuery.current = query;
34	  }, [query]);
35	
36	  // Using a string state here as users can write arbitrary text in the input field.
37	  // Only if the validation passes, the value will be converted to a number.
38	  const [pendingLimit, setPendingLimit] = useState(limit.toString());
39	  useEffect(() => {
40	    setPendingLimit(limit.toString());
41	  }, [limit]);
42	  // limit must be empty or an integer between 1 and MAX_LIMIT
43	  const pendingLimitHasError = !(
44	    pendingLimit === '' ||
45	    (/^[0-9]+$/.test(pendingLimit) &&
46	      parseInt(pendingLimit) >= 1 &&
47	      parseInt(pendingLimit) <= MAX_LIMIT)
48	  );
49	
50	  const runPendingQuery = useCallback(() => {
51	    if (pendingLimitHasError) {
52	      return;
53	    }
54	
55	    runQuery({
56	      query: pendingQuery.current,
57	      limit: pendingLimit === '' ? undefined : parseInt(pendingLimit),
58	    });
59	  }, [runQuery, pendingLimit, pendingLimitHasError]);
60	
61	  return (
62	    <>
63	      <Stack style={{ flexGrow: 1 }}>
64	        <label htmlFor="traceql-input">{t('Query')}</label>
65	        <TraceQLEditor
66	          tempo={tempo}
67	          query={query}
68	          setQuery={setPendingQuery}
69	          runQuery={runPendingQuery}
70	        />
71	      </Stack>
72	      <Stack>
73	        <label htmlFor="limit-input">{t('Max Traces')}</label>
74	        <TextInput
75	          id="limit-input"
76	          value={pendingLimit}
77	          title={
78	            pendingLimitHasError
79	              ? t('The number of search results must be between 1 and {{max}}', { max: MAX_LIMIT })
80	              : ''
81	          }
82	          validated={pendingLimitHasError ? 'error' : 'default'}
83	          onChange={(_evt, value) => setPendingLimit(value)}
84	          aria-label="max traces"
85	          size={5}
86	        />
87	      </Stack>
88	      <Stack style={{ height: 'auto', flexDirection: 'column-reverse' }}>
89	        <Button variant="primary" onClick={runPendingQuery}>
90	          {t('Run query')}
91	        </Button>
92	      </Stack>
93	    </>
94	  );
95	}

